// Gugustus - NoFall.java (OnGround + NoGround modes)
// Reproduced from actual 1.8.9 client source
@EventTarget
public void onPacketSend(EventSendPacket eventSendPacket) {
  Packet packet = eventSendPacket.getPacket();

  // OnGround mode: force onGround=true to prevent fall damage
  if (var3.equals("OnGround")) {
    if (packet instanceof C03PacketPlayer &&
        mc.thePlayer.fallDistance > fallDistance.getValue()) {
      C03PacketPlayer c03 = (C03PacketPlayer) packet;
      c03.setOnGround(true);  // tell server we are on ground
      // Also send an extra ground packet to be sure
      mc.thePlayer.sendQueue.addToSendQueueDirect(
        new C03PacketPlayer(true));
    }
  }

  // NoGround mode: force onGround=false always (for bypass)
  if (var3.equals("NoGround")) {
    if (packet instanceof C03PacketPlayer) {
      C03PacketPlayer c03 = (C03PacketPlayer) packet;
      c03.setOnGround(false);
    }
  }

  // Stop mode: completely freeze fall packets
  if (var3.equals("Stop")) {
    if (packet instanceof C03PacketPlayer &&
        mc.thePlayer.fallDistance > 3) {
      eventSendPacket.setCancelled(true);
    }
  }
}

