@EventTarget
public void onPacketSend(EventSendPacket eventSendPacket) {
  // Spoof position with large offset to confuse anti-cheat
  if (eventSendPacket.getPacket() instanceof C03PacketPlayer) {
    C03PacketPlayer c03 = (C03PacketPlayer) eventSendPacket.getPacket();
    c03.setX(mc.thePlayer.posX + 1000);
    c03.setZ(mc.thePlayer.posZ + 1000);
    c03.setOnGround(false);
  }
}

