// Gugustus - Blink.java (packet buffer + release)
// Reproduced from actual 1.8.9 client source
private ArrayList<Packet> packets = new ArrayList<>();

@EventTarget
public void onPacketSend(EventSendPacket event) {
  if (event.getPacket() instanceof C03PacketPlayer ||
      event.getPacket() instanceof C02PacketUseEntity ||
      event.getPacket() instanceof C0BPacketEntityAction) {
    packets.add(event.getPacket());  // store
    event.setCancelled(true);        // cancel send
  }
}

@Override
public void onDisable() {
  // Flush all held packets to server at once
  // The server processes them in order, teleporting the player
  for (Packet p : packets) {
    mc.thePlayer.sendQueue.addToSendQueue(p);
  }
  packets.clear();
}

